#\!/usr/bin/env python3
"""Dream Abroad - Update v8: Client Edit + Room/Bed Linking + Auto-create beds"""
import base64, os, sys

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")
if not os.path.isdir(PROJECT):
    print("ERRO: Pasta ~/Desktop/dream-abroad nao encontrada")
    sys.exit(1)

files = {}
files["frontend/src/pages/Clients.tsx"] = ""
files["frontend/src/pages/ClientProfile.tsx"] = ""
files["frontend/src/pages/PropertyProfile.tsx"] = ""
files["backend/routers/clients.py"] = ""
files["backend/routers/rooms.py"] = ""
files["backend/schemas.py"] = ""

print("Aplicando Update v8...")
print()
for rel, b64 in files.items():
    full = os.path.join(PROJECT, rel)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"  OK: {rel}")

# Fix api.ts baseURL
api_path = os.path.join(PROJECT, "frontend/src/services/api.ts")
if os.path.exists(api_path):
    with open(api_path, "r") as f:
        content = f.read()
    if "http://localhost:8000" in content:
        content = content.replace("http://localhost:8000", "")
        with open(api_path, "w") as f:
            f.write(content)
        print("  OK: api.ts baseURL corrigido")

print()
print("=" * 55)
print("  Update v8 aplicado com sucesso\!")
print("=" * 55)
print()
print("O que mudou:")
print("  CLIENTES:")
print("    - Botao Editar (lapis) na tabela de clientes")
print("    - Modal de edicao completo com Propriedade/Quarto/Cama")
print("    - Dropdowns em cascata (propriedade > quarto > cama)")
print()
print("  PERFIL DO CLIENTE:")
print("    - Secao Acomodacao com botao Alterar")
print("    - Botao Editar no topo do perfil")
print("    - Mostra quarto/cama no header")
print()
print("  QUARTOS (PropertyProfile):")
print("    - Valor agora eh TOTAL do quarto")
print("    - Mostra calculo por cama (ex: 1500/3 = 500/cama)")
print("    - Opcao de criar camas automaticamente")
print("    - Valor de cada cama mostrado no card")
print()
print("  BACKEND:")
print("    - Update de cliente retorna nomes corretos")
print("    - Auto-criacao de camas com valor dividido")
print("    - room_id/bed_id no endpoint de profile")
print()
print("Para aplicar, reinicie o backend:")
print("  lsof -ti:8000 | xargs kill -9")
print("  cd ~/Desktop/dream-abroad/backend")
print("  source venv/bin/activate && uvicorn main:app --reload")